mapper.select:
SELECT e.id, e.title, e.subtitle, e.major_id, e.course_id, e.is_final_exam, e.status, e.recommended, e.difficulty, e.duration, e.total_score, e.pass_score, e.introduction, e.notes, e.examiner, e.logo, e.question_range_type, e.create_time, e.update_time, e.create_by, e.update_by, e.deleted, m.name AS major_name, c.name AS course_name FROM edu_exam e LEFT JOIN edu_major m ON e.major_id = m.id AND m.deleted = 0 LEFT JOIN edu_course c ON e.course_id = c.id AND c.deleted = 0 WHERE e.deleted = 0
AND e.title LIKE CONCAT('%', #{query.title}, '%')
AND e.course_id = #{query.courseId}
AND e.status = #{query.status}
ORDER BY e.id DESC

SELECT COUNT(*)
FROM edu_exam e
WHERE e.deleted = 0

    AND e.title LIKE CONCAT('%', #{query.title}, '%')


    AND e.course_id = #{query.courseId}


    AND e.status = #{query.status}
